import type { LexicalEditor } from "lexical";
import { HTML_EXAMPLE, MARKDOWN_EXAMPLE } from "./constants";
import {
  createEmptyEditorState,
  loadMarkdownContent,
  replaceEditorHtmlContent,
} from "./utils";

export const copyEditorOutput = async (value: string) => {
  await navigator.clipboard.writeText(value);
};

export const resetEditorContent = (editor: LexicalEditor) => {
  createEmptyEditorState(editor);
};

export const loadEditorHtmlExample = (editor: LexicalEditor) => {
  replaceEditorHtmlContent(editor, HTML_EXAMPLE);
};

export const loadEditorMarkdownExample = (editor: LexicalEditor) => {
  loadMarkdownContent(editor, MARKDOWN_EXAMPLE);
};

/** Shape of a single color entry in the palette. */
export interface ColorSwatch {
  /** Human-readable label (used as aria-label on the swatch button). */
  label: string;
  /** CSS color value, e.g. "#ef4444". */
  value: string;
}

/**
 * Default color palette shared by the text color and background color pickers.
 *
 * To customise the available swatches, edit this array — the order determines
 * the rendering order in the grid. Both pickers import this constant as their
 * default, but each `<ColorSwatches>` instance also accepts a custom `palette`
 * prop if you need diverging sets.
 */
export const COLOR_PALETTE: ColorSwatch[] = [
  { label: "Black", value: "#1a1a1a" },
  { label: "Dark gray", value: "#525252" },
  { label: "Gray", value: "#a3a3a3" },
  { label: "White", value: "#ffffff" },
  { label: "Red", value: "#ef4444" },
  { label: "Orange", value: "#f97316" },
  { label: "Yellow", value: "#eab308" },
  { label: "Green", value: "#22c55e" },
  { label: "Cyan", value: "#06b6d4" },
  { label: "Blue", value: "#3b82f6" },
  { label: "Violet", value: "#8b5cf6" },
  { label: "Pink", value: "#ec4899" },
  { label: "Light red", value: "#fca5a5" },
  { label: "Light yellow", value: "#fde68a" },
  { label: "Light green", value: "#bbf7d0" },
  { label: "Light blue", value: "#bfdbfe" },
];

import { deepStrictEqual, strictEqual } from "node:assert/strict";
import { describe, test } from "node:test";
import {
  DEFAULT_EDITOR_CHROME,
  DEFAULT_EDITOR_FEATURES,
  renderEditorSlot,
  resolveEditorChrome,
  resolveEditorFeatures,
} from "./composition";

describe("editor composition", () => {
  test("resolves feature flags over defaults", () => {
    deepStrictEqual(resolveEditorFeatures(), DEFAULT_EDITOR_FEATURES);
    deepStrictEqual(
      resolveEditorFeatures({
        floatingToolbar: false,
        history: false,
      }),
      {
        ...DEFAULT_EDITOR_FEATURES,
        floatingToolbar: false,
        history: false,
      }
    );
  });

  test("resolves chrome options over defaults", () => {
    deepStrictEqual(resolveEditorChrome(), DEFAULT_EDITOR_CHROME);
    deepStrictEqual(resolveEditorChrome({ header: false, outputs: false }), {
      ...DEFAULT_EDITOR_CHROME,
      header: false,
      outputs: false,
    });
  });

  test("renders slots as values or callbacks", () => {
    strictEqual(renderEditorSlot("header", { value: 1 }), "header");
    strictEqual(
      renderEditorSlot(({ value }: { value: number }) => value * 2, {
        value: 3,
      }),
      6
    );
    strictEqual(renderEditorSlot(undefined, { value: 1 }), undefined);
  });
});

import type { ReactNode } from "react";
import type { EditorChromeOptions, EditorFeatureFlags } from "./types";

export const DEFAULT_EDITOR_FEATURES = {
  collapsible: true,
  draggableBlocks: true,
  floatingLinkEditor: true,
  floatingToolbar: true,
  focusOnMount: true,
  history: true,
  images: true,
  layouts: true,
  markdownShortcuts: true,
  seedContent: true,
  slashCommand: true,
  tabIndentation: true,
  tables: true,
  youtube: true,
} as const satisfies Required<EditorFeatureFlags>;

export const DEFAULT_EDITOR_CHROME = {
  actionBar: true,
  footer: true,
  header: true,
  outputs: true,
  shell: true,
} as const satisfies Required<EditorChromeOptions>;

export type ResolvedEditorFeatureFlags = Required<EditorFeatureFlags>;
export type ResolvedEditorChromeOptions = Required<EditorChromeOptions>;

export const resolveEditorFeatures = (
  features?: EditorFeatureFlags
): ResolvedEditorFeatureFlags => {
  return {
    ...DEFAULT_EDITOR_FEATURES,
    ...features,
  };
};

export const resolveEditorChrome = (
  chrome?: EditorChromeOptions
): ResolvedEditorChromeOptions => {
  return {
    ...DEFAULT_EDITOR_CHROME,
    ...chrome,
  };
};

export const renderEditorSlot = <T>(
  slot: ReactNode | ((context: T) => ReactNode) | undefined,
  context: T
): ReactNode | undefined => {
  if (typeof slot === "function") {
    return slot(context);
  }

  return slot;
};

import { deepStrictEqual, strictEqual } from "node:assert/strict";
import { describe, test } from "node:test";
import { ParagraphNode } from "lexical";
import { createEditorConfig, DEFAULT_EDITOR_NODES } from "./config";

describe("editor config", () => {
  test("builds config with defaults", () => {
    const config = createEditorConfig({ editable: true });

    strictEqual(config.editable, true);
    strictEqual(config.namespace, "PytahEditor");
    deepStrictEqual(config.nodes, DEFAULT_EDITOR_NODES);
    strictEqual(typeof config.onError, "function");
  });

  test("appends extra nodes without dropping built-ins", () => {
    const config = createEditorConfig({
      editable: false,
      namespace: "CustomEditor",
      nodes: [ParagraphNode],
    });

    strictEqual(config.editable, false);
    strictEqual(config.namespace, "CustomEditor");
    strictEqual(config.nodes?.length, DEFAULT_EDITOR_NODES.length + 1);
    strictEqual(config.nodes?.at(-1), ParagraphNode);
  });
});

import { CodeHighlightNode, CodeNode } from "@lexical/code";
import { HorizontalRuleNode } from "@lexical/extension";
import { AutoLinkNode, LinkNode } from "@lexical/link";
import { ListItemNode, ListNode } from "@lexical/list";
import type { InitialConfigType } from "@lexical/react/LexicalComposer";
import { HeadingNode, QuoteNode } from "@lexical/rich-text";
import { TableCellNode, TableNode, TableRowNode } from "@lexical/table";
import { CollapsibleContainerNode } from "./nodes/collapsible/container-node";
import { CollapsibleContentNode } from "./nodes/collapsible/content-node";
import { CollapsibleTitleNode } from "./nodes/collapsible/title-node";
import { ImageNode } from "./nodes/image/node";
import { LayoutContainerNode } from "./nodes/layout/container-node";
import { LayoutItemNode } from "./nodes/layout/item-node";
import { YouTubeNode } from "./nodes/youtube/node";
import { editorTheme } from "./theme";

function onError(error: Error) {
  console.error("[Editor]", error);
}

export const DEFAULT_EDITOR_NODES = [
  HeadingNode,
  QuoteNode,
  ListNode,
  ListItemNode,
  CodeNode,
  CodeHighlightNode,
  LinkNode,
  AutoLinkNode,
  HorizontalRuleNode,
  ImageNode,
  YouTubeNode,
  CollapsibleContainerNode,
  CollapsibleTitleNode,
  CollapsibleContentNode,
  LayoutContainerNode,
  LayoutItemNode,
  TableNode,
  TableRowNode,
  TableCellNode,
];

interface CreateEditorConfigOptions {
  editable: boolean;
  namespace?: string;
  nodes?: NonNullable<InitialConfigType["nodes"]>;
}

export const createEditorConfig = ({
  editable,
  namespace = "PytahEditor",
  nodes,
}: CreateEditorConfigOptions): InitialConfigType => {
  return {
    editable,
    namespace,
    nodes: nodes ? [...DEFAULT_EDITOR_NODES, ...nodes] : DEFAULT_EDITOR_NODES,
    onError,
    theme: editorTheme,
  };
};

import { addClassNamesToElement, IS_CHROME } from "@lexical/utils";
import {
  $getSiblingCaret,
  $isElementNode,
  $rewindSiblingCaret,
  type DOMConversionMap,
  type DOMConversionOutput,
  type DOMExportOutput,
  type EditorConfig,
  ElementNode,
  isHTMLElement,
  type LexicalEditor,
  type LexicalNode,
  type LexicalUpdateJSON,
  type NodeKey,
  type RangeSelection,
  type SerializedElementNode,
  type Spread,
} from "lexical";
import { setDomHiddenUntilFound } from "./dom-utils";

export type SerializedCollapsibleContainerNode = Spread<
  {
    open: boolean;
  },
  SerializedElementNode
>;

const applyContainerOpenState = (dom: HTMLElement, open: boolean) => {
  dom.dataset.open = open ? "true" : "false";

  const titleDom = dom.firstElementChild;
  if (isHTMLElement(titleDom)) {
    titleDom.dataset.open = open ? "true" : "false";
  }
};

const convertDetailsElement = (domNode: HTMLElement): DOMConversionOutput => {
  const detailsElement = domNode as HTMLDetailsElement;
  return {
    node: $createCollapsibleContainerNode(detailsElement.open ?? true),
  };
};

const convertCollapsibleContainerElement = (
  domNode: HTMLElement
): DOMConversionOutput => {
  return {
    node: $createCollapsibleContainerNode(domNode.dataset.open !== "false"),
  };
};

export class CollapsibleContainerNode extends ElementNode {
  __open: boolean;

  constructor(open: boolean, key?: NodeKey) {
    super(key);
    this.__open = open;
  }

  static getType(): string {
    return "collapsible-container";
  }

  static clone(node: CollapsibleContainerNode): CollapsibleContainerNode {
    return new CollapsibleContainerNode(node.__open, node.__key);
  }

  static importDOM(): DOMConversionMap | null {
    return {
      details: () => ({
        conversion: convertDetailsElement,
        priority: 1,
      }),
      div: (domNode: HTMLElement) => {
        if (!domNode.hasAttribute("data-lexical-collapsible-container")) {
          return null;
        }

        return {
          conversion: convertCollapsibleContainerElement,
          priority: 2,
        };
      },
    };
  }

  static importJSON(
    serializedNode: SerializedCollapsibleContainerNode
  ): CollapsibleContainerNode {
    return $createCollapsibleContainerNode().updateFromJSON(serializedNode);
  }

  createDOM(config: EditorConfig, editor: LexicalEditor): HTMLElement {
    let dom: HTMLElement;

    if (IS_CHROME) {
      dom = document.createElement("div");
    } else {
      const detailsDom = document.createElement("details");
      detailsDom.addEventListener("toggle", () => {
        const open = editor.getEditorState().read(() => this.getOpen());
        if (detailsDom.open !== open) {
          editor.update(() => {
            this.toggleOpen();
          });
        }
      });
      dom = detailsDom;
    }

    dom.setAttribute("data-lexical-collapsible-container", "true");
    applyContainerOpenState(dom, this.__open);

    if (this.__open) {
      dom.setAttribute("open", "");
    }

    if (typeof config.theme.collapsibleContainer === "string") {
      addClassNamesToElement(dom, config.theme.collapsibleContainer);
    }

    return dom;
  }

  updateDOM(prevNode: this, dom: HTMLElement): boolean {
    if (prevNode.__open === this.__open) {
      return false;
    }

    applyContainerOpenState(dom, this.__open);

    if (this.__open) {
      dom.setAttribute("open", "");
    } else {
      dom.removeAttribute("open");
    }

    if (IS_CHROME) {
      const contentDom = dom.children[1];
      if (!isHTMLElement(contentDom)) {
        throw new Error("Expected collapsible content DOM element");
      }

      if (this.__open) {
        contentDom.hidden = false;
      } else {
        setDomHiddenUntilFound(contentDom);
      }
    } else if (dom instanceof HTMLDetailsElement) {
      dom.open = this.__open;
    }

    return false;
  }

  exportDOM(): DOMExportOutput {
    const element = document.createElement("details");
    element.setAttribute("data-lexical-collapsible-container", "true");
    element.dataset.open = this.__open ? "true" : "false";

    if (this.__open) {
      element.setAttribute("open", "");
    }

    return { element };
  }

  exportJSON(): SerializedCollapsibleContainerNode {
    return {
      ...super.exportJSON(),
      open: this.__open,
      type: "collapsible-container",
      version: 1,
    };
  }

  updateFromJSON(
    serializedNode: LexicalUpdateJSON<SerializedCollapsibleContainerNode>
  ): this {
    return super.updateFromJSON(serializedNode).setOpen(serializedNode.open);
  }

  collapseAtStart(selection: RangeSelection): boolean {
    const nodesToInsert: LexicalNode[] = [];

    for (const child of this.getChildren()) {
      if ($isElementNode(child)) {
        nodesToInsert.push(...child.getChildren());
      }
    }

    const caret = $rewindSiblingCaret($getSiblingCaret(this, "previous"));
    caret.splice(1, nodesToInsert);

    const [firstChild] = nodesToInsert;
    if (firstChild) {
      firstChild.selectStart().deleteCharacter(true);
    }

    return selection.isCollapsed();
  }

  isShadowRoot(): boolean {
    return true;
  }

  canBeEmpty(): boolean {
    return false;
  }

  getOpen(): boolean {
    return this.getLatest().__open;
  }

  setOpen(open: boolean): this {
    const writable = this.getWritable();
    writable.__open = open;
    return writable;
  }

  toggleOpen(): this {
    return this.setOpen(!this.getOpen());
  }
}

export function $createCollapsibleContainerNode(
  open = true
): CollapsibleContainerNode {
  return new CollapsibleContainerNode(open);
}

export function $isCollapsibleContainerNode(
  node: LexicalNode | null | undefined
): node is CollapsibleContainerNode {
  return node instanceof CollapsibleContainerNode;
}

import { addClassNamesToElement, IS_CHROME } from "@lexical/utils";
import type {
  DOMConversionMap,
  DOMConversionOutput,
  DOMExportOutput,
  EditorConfig,
  LexicalEditor,
  LexicalNode,
  SerializedElementNode,
} from "lexical";
import { ElementNode } from "lexical";
import { $isCollapsibleContainerNode } from "./container-node";
import { domOnBeforeMatch, setDomHiddenUntilFound } from "./dom-utils";

export type SerializedCollapsibleContentNode = SerializedElementNode;

const convertCollapsibleContentElement = (): DOMConversionOutput => {
  return {
    node: $createCollapsibleContentNode(),
  };
};

export class CollapsibleContentNode extends ElementNode {
  static getType(): string {
    return "collapsible-content";
  }

  static clone(node: CollapsibleContentNode): CollapsibleContentNode {
    return new CollapsibleContentNode(node.__key);
  }

  static importDOM(): DOMConversionMap | null {
    return {
      div: (domNode: HTMLElement) => {
        if (!domNode.hasAttribute("data-lexical-collapsible-content")) {
          return null;
        }

        return {
          conversion: convertCollapsibleContentElement,
          priority: 2,
        };
      },
    };
  }

  static importJSON(
    serializedNode: SerializedCollapsibleContentNode
  ): CollapsibleContentNode {
    return $createCollapsibleContentNode().updateFromJSON(serializedNode);
  }

  createDOM(config: EditorConfig, editor: LexicalEditor): HTMLElement {
    const dom = document.createElement("div");
    dom.setAttribute("data-lexical-collapsible-content", "true");

    if (typeof config.theme.collapsibleContent === "string") {
      addClassNamesToElement(dom, config.theme.collapsibleContent);
    }

    if (IS_CHROME) {
      editor.getEditorState().read(() => {
        const containerNode = this.getParentOrThrow();
        if (!$isCollapsibleContainerNode(containerNode)) {
          throw new Error(
            "Collapsible content expects a collapsible container"
          );
        }

        if (!containerNode.getOpen()) {
          setDomHiddenUntilFound(dom);
        }
      });

      domOnBeforeMatch(dom, () => {
        editor.update(() => {
          const containerNode = this.getParentOrThrow().getLatest();
          if (!$isCollapsibleContainerNode(containerNode)) {
            throw new Error(
              "Collapsible content expects a collapsible container"
            );
          }

          if (!containerNode.getOpen()) {
            containerNode.toggleOpen();
          }
        });
      });
    }

    return dom;
  }

  updateDOM(): boolean {
    return false;
  }

  exportDOM(): DOMExportOutput {
    const element = document.createElement("div");
    element.setAttribute("data-lexical-collapsible-content", "true");
    return { element };
  }

  exportJSON(): SerializedCollapsibleContentNode {
    return {
      ...super.exportJSON(),
      type: "collapsible-content",
      version: 1,
    };
  }

  isShadowRoot(): boolean {
    return true;
  }

  canBeEmpty(): boolean {
    return false;
  }
}

export function $createCollapsibleContentNode(): CollapsibleContentNode {
  return new CollapsibleContentNode();
}

export function $isCollapsibleContentNode(
  node: LexicalNode | null | undefined
): node is CollapsibleContentNode {
  return node instanceof CollapsibleContentNode;
}

export const setDomHiddenUntilFound = (dom: HTMLElement) => {
  dom.setAttribute("hidden", "until-found");
};

export const domOnBeforeMatch = (dom: HTMLElement, callback: () => void) => {
  const beforeMatchDom = dom as HTMLElement & {
    onbeforematch: null | (() => void);
  };
  beforeMatchDom.onbeforematch = callback;
};

import { addClassNamesToElement, IS_CHROME } from "@lexical/utils";
import type {
  DOMConversionMap,
  DOMConversionOutput,
  DOMExportOutput,
  EditorConfig,
  LexicalEditor,
  LexicalNode,
  RangeSelection,
  SerializedElementNode,
} from "lexical";
import { $createParagraphNode, $isElementNode, ElementNode } from "lexical";
import { $isCollapsibleContainerNode } from "./container-node";
import { $isCollapsibleContentNode } from "./content-node";

export type SerializedCollapsibleTitleNode = SerializedElementNode;

const convertSummaryElement = (): DOMConversionOutput => {
  return {
    node: $createCollapsibleTitleNode(),
  };
};

export class CollapsibleTitleNode extends ElementNode {
  static getType(): string {
    return "collapsible-title";
  }

  static clone(node: CollapsibleTitleNode): CollapsibleTitleNode {
    return new CollapsibleTitleNode(node.__key);
  }

  static importDOM(): DOMConversionMap | null {
    return {
      summary: () => ({
        conversion: convertSummaryElement,
        priority: 1,
      }),
    };
  }

  static importJSON(
    serializedNode: SerializedCollapsibleTitleNode
  ): CollapsibleTitleNode {
    return $createCollapsibleTitleNode().updateFromJSON(serializedNode);
  }

  createDOM(config: EditorConfig, editor: LexicalEditor): HTMLElement {
    const dom = document.createElement("summary");
    dom.setAttribute("data-lexical-collapsible-trigger", "true");

    const open = editor.getEditorState().read(() => {
      const container = this.getParent();
      return $isCollapsibleContainerNode(container)
        ? container.getOpen()
        : true;
    });
    dom.dataset.open = open ? "true" : "false";

    if (typeof config.theme.collapsibleTitle === "string") {
      addClassNamesToElement(dom, config.theme.collapsibleTitle);
    }

    if (IS_CHROME) {
      dom.addEventListener("click", () => {
        editor.update(() => {
          const container = this.getLatest().getParentOrThrow();
          if (!$isCollapsibleContainerNode(container)) {
            throw new Error(
              "Collapsible title expects a collapsible container"
            );
          }

          container.toggleOpen();
        });
      });
    }

    return dom;
  }

  updateDOM(): boolean {
    return false;
  }

  exportDOM(): DOMExportOutput {
    return { element: document.createElement("summary") };
  }

  exportJSON(): SerializedCollapsibleTitleNode {
    return {
      ...super.exportJSON(),
      type: "collapsible-title",
      version: 1,
    };
  }

  insertNewAfter(_: RangeSelection, restoreSelection = true): ElementNode {
    const containerNode = this.getParentOrThrow();
    if (!$isCollapsibleContainerNode(containerNode)) {
      throw new Error("Collapsible title expects a collapsible container");
    }

    if (containerNode.getOpen()) {
      const contentNode = this.getNextSibling();
      if (!$isCollapsibleContentNode(contentNode)) {
        throw new Error(
          "Collapsible title expects a collapsible content sibling"
        );
      }

      const firstChild = contentNode.getFirstChild();
      if ($isElementNode(firstChild)) {
        return firstChild;
      }

      const paragraph = $createParagraphNode();
      contentNode.append(paragraph);
      return paragraph;
    }

    const paragraph = $createParagraphNode();
    containerNode.insertAfter(paragraph, restoreSelection);
    return paragraph;
  }

  canBeEmpty(): boolean {
    return false;
  }
}

export function $createCollapsibleTitleNode(): CollapsibleTitleNode {
  return new CollapsibleTitleNode();
}

export function $isCollapsibleTitleNode(
  node: LexicalNode | null | undefined
): node is CollapsibleTitleNode {
  return node instanceof CollapsibleTitleNode;
}

"use client";

import { addClassNamesToElement } from "@lexical/utils";
import type {
  DOMConversionMap,
  DOMConversionOutput,
  DOMExportOutput,
  EditorConfig,
  LexicalNode,
  LexicalUpdateJSON,
  NodeKey,
  SerializedLexicalNode,
  Spread,
} from "lexical";
import { DecoratorNode } from "lexical";
import type { JSX } from "react";
import { ImageComponent } from "../../../plugins/image/component";

export type SerializedImageNode = Spread<
  {
    alignment?: ImageAlignment;
    altText: string;
    height: number | "inherit";
    src: string;
    width: number | "inherit";
  },
  SerializedLexicalNode
>;

export type ImageAlignment = "left" | "center" | "right";

export interface ImagePayload {
  alignment?: ImageAlignment;
  altText: string;
  height?: number | "inherit";
  key?: NodeKey;
  src: string;
  width?: number | "inherit";
}

const getImageAlignment = (domNode: HTMLImageElement): ImageAlignment => {
  const align = domNode.getAttribute("align");

  if (align === "center" || align === "right" || align === "left") {
    return align;
  }

  const { marginLeft, marginRight } = domNode.style;

  if (marginLeft === "auto" && marginRight === "auto") {
    return "center";
  }

  if (marginLeft === "auto") {
    return "right";
  }

  return "left";
};

const convertImageElement = (domNode: Node): DOMConversionOutput | null => {
  if (!(domNode instanceof HTMLImageElement)) {
    return null;
  }

  const src = domNode.getAttribute("src");
  if (!src || src.startsWith("file:///")) {
    return null;
  }

  return {
    node: $createImageNode({
      alignment: getImageAlignment(domNode),
      altText: domNode.getAttribute("alt") ?? "",
      height: domNode.height || undefined,
      src,
      width: domNode.width || undefined,
    }),
  };
};

export class ImageNode extends DecoratorNode<JSX.Element> {
  __alignment: ImageAlignment;
  __altText: string;
  __height: number | "inherit";
  __src: string;
  __width: number | "inherit";

  constructor(
    src: string,
    altText: string,
    alignment: ImageAlignment = "left",
    width: number | "inherit" = "inherit",
    height: number | "inherit" = "inherit",
    key?: NodeKey
  ) {
    super(key);
    this.__src = src;
    this.__altText = altText;
    this.__alignment = alignment;
    this.__width = width;
    this.__height = height;
  }

  static getType(): string {
    return "image";
  }

  static clone(node: ImageNode): ImageNode {
    return new ImageNode(
      node.__src,
      node.__altText,
      node.__alignment,
      node.__width,
      node.__height,
      node.__key
    );
  }

  static importDOM(): DOMConversionMap | null {
    return {
      img: () => ({
        conversion: convertImageElement,
        priority: 2,
      }),
    };
  }

  static importJSON(serializedNode: SerializedImageNode): ImageNode {
    return $createImageNode({
      alignment: serializedNode.alignment,
      altText: serializedNode.altText,
      height: serializedNode.height,
      src: serializedNode.src,
      width: serializedNode.width,
    }).updateFromJSON(serializedNode);
  }

  updateFromJSON(serializedNode: LexicalUpdateJSON<SerializedImageNode>): this {
    return super
      .updateFromJSON(serializedNode)
      .setAlignment(serializedNode.alignment ?? "left")
      .setAltText(serializedNode.altText)
      .setHeight(serializedNode.height)
      .setSrc(serializedNode.src)
      .setWidth(serializedNode.width);
  }

  exportDOM(): DOMExportOutput {
    const element = document.createElement("img");
    element.setAttribute("src", this.__src);
    element.setAttribute("alt", this.__altText);
    element.style.display = "block";

    if (this.__alignment === "center") {
      element.style.marginLeft = "auto";
      element.style.marginRight = "auto";
    } else if (this.__alignment === "right") {
      element.style.marginLeft = "auto";
      element.style.marginRight = "0";
    }

    if (this.__width !== "inherit") {
      element.width = this.__width;
    }

    if (this.__height !== "inherit") {
      element.height = this.__height;
    }

    return { element };
  }

  exportJSON(): SerializedImageNode {
    return {
      ...super.exportJSON(),
      alignment: this.__alignment,
      altText: this.__altText,
      height: this.__height,
      src: this.__src,
      type: "image",
      version: 1,
      width: this.__width,
    };
  }

  createDOM(config: EditorConfig): HTMLElement {
    const span = document.createElement("span");

    if (typeof config.theme.image === "string") {
      addClassNamesToElement(span, config.theme.image);
    }

    return span;
  }

  updateDOM(): false {
    return false;
  }

  decorate(): JSX.Element {
    return (
      <ImageComponent
        alignment={this.__alignment}
        altText={this.__altText}
        height={this.__height}
        nodeKey={this.getKey()}
        src={this.__src}
        width={this.__width}
      />
    );
  }

  isInline(): false {
    return false;
  }

  getSrc(): string {
    return this.getLatest().__src;
  }

  getAltText(): string {
    return this.getLatest().__altText;
  }

  getAlignment(): ImageAlignment {
    return this.getLatest().__alignment;
  }

  getWidth(): number | "inherit" {
    return this.getLatest().__width;
  }

  getHeight(): number | "inherit" {
    return this.getLatest().__height;
  }

  setAltText(altText: string): this {
    const writable = this.getWritable();
    writable.__altText = altText;
    return writable;
  }

  setAlignment(alignment: ImageAlignment): this {
    const writable = this.getWritable();
    writable.__alignment = alignment;
    return writable;
  }

  setWidth(width: number | "inherit"): this {
    const writable = this.getWritable();
    writable.__width = width;
    return writable;
  }

  setWidthAndHeight(
    width: number | "inherit",
    height: number | "inherit"
  ): this {
    const writable = this.getWritable();
    writable.__width = width;
    writable.__height = height;
    return writable;
  }

  setHeight(height: number | "inherit"): this {
    const writable = this.getWritable();
    writable.__height = height;
    return writable;
  }

  setSrc(src: string): this {
    const writable = this.getWritable();
    writable.__src = src;
    return writable;
  }
}

export function $createImageNode({
  alignment,
  altText,
  height,
  key,
  src,
  width,
}: ImagePayload): ImageNode {
  return new ImageNode(
    src,
    altText,
    alignment ?? "left",
    width ?? "inherit",
    height ?? "inherit",
    key
  );
}

export function $isImageNode(
  node: LexicalNode | null | undefined
): node is ImageNode {
  return node instanceof ImageNode;
}

import { addClassNamesToElement } from "@lexical/utils";
import type {
  DOMConversionMap,
