const DRAG_MENU_CLASS_NAME = "editor-draggable-block-menu";

export function DraggableBlockPlugin() {
  const [editor] = useLexicalComposerContext();
  const isEditable = useLexicalEditable();
  const menuRef = useRef<HTMLDivElement>(null);
  const targetLineRef = useRef<HTMLDivElement>(null);
  const [anchorElem, setAnchorElem] = useState<HTMLElement | null>(null);

  useEffect(() => {
    return editor.registerRootListener((rootElement) => {
      setAnchorElem(rootElement?.parentElement ?? null);
    });
  }, [editor]);

  const isOnMenu = useCallback(
    (element: HTMLElement) =>
      Boolean(element.closest(`.${DRAG_MENU_CLASS_NAME}`)),
    []
  );

  if (!(isEditable && anchorElem)) {
    return null;
  }

  return (
    <DraggableBlockPlugin_EXPERIMENTAL
      anchorElem={anchorElem}
      isOnMenu={isOnMenu}
      menuComponent={
        <div
          className={`${DRAG_MENU_CLASS_NAME} absolute top-0 left-0 z-40 flex cursor-grab items-center gap-0.5 rounded-md p-0.5 text-muted-foreground opacity-0 transition-[transform,opacity] duration-150 ease-in-out active:cursor-grabbing`}
          ref={menuRef}
        >
          <div className="flex size-4 items-center justify-center rounded-sm opacity-50 transition hover:bg-muted hover:opacity-100">
            <GripVerticalIcon className="size-3.5" />
          </div>
        </div>
      }
      menuRef={menuRef}
      targetLineComponent={
        <div
          className="pointer-events-none absolute top-0 left-0 z-30 h-1 rounded-full bg-primary opacity-0"
          ref={targetLineRef}
        />
      }
      targetLineRef={targetLineRef}
    />
  );
}

import {
  $createLinkNode,
  $isAutoLinkNode,
  TOGGLE_LINK_COMMAND,
} from "@lexical/link";
import { $patchStyleText } from "@lexical/selection";
import {
  $getSelection,
  $isRangeSelection,
  FORMAT_TEXT_COMMAND,
  type LexicalEditor,
} from "lexical";
import {
  isValidEditorLinkUrl,
  normalizeEditorLinkUrl,
} from "../link-behavior/utils";
import {
  getFloatingToolbarSelectedNode,
  getSelectedLinkNode,
} from "./selection";

export const submitToolbarLink = (
  editor: LexicalEditor,
  linkUrl: string
): string => {
  const normalizedLinkUrl = normalizeEditorLinkUrl(linkUrl);

  if (isValidEditorLinkUrl(normalizedLinkUrl)) {
    editor.update(() => {
      editor.dispatchCommand(TOGGLE_LINK_COMMAND, normalizedLinkUrl);

      const selection = $getSelection();
      if (!$isRangeSelection(selection)) {
        return;
      }

      const selectedNode = getFloatingToolbarSelectedNode(selection);
      const linkNode = getSelectedLinkNode(selectedNode);
      if (!$isAutoLinkNode(linkNode)) {
        return;
      }

      const replacementLinkNode = $createLinkNode(linkNode.getURL(), {
        rel: linkNode.__rel,
        target: linkNode.__target,
        title: linkNode.__title,
      });
      linkNode.replace(replacementLinkNode, true);
    });
  } else {
    editor.dispatchCommand(TOGGLE_LINK_COMMAND, null);
  }

  return "";
};

export const clearToolbarLink = (editor: LexicalEditor) => {
  editor.dispatchCommand(TOGGLE_LINK_COMMAND, null);
};

export const toggleToolbarFormat = (
  editor: LexicalEditor,
  format:
    | "bold"
    | "italic"
    | "underline"
    | "strikethrough"
    | "code"
    | "highlight"
) => {
  editor.dispatchCommand(FORMAT_TEXT_COMMAND, format);
};

/**
 * Applies an inline `color` CSS property to the current Lexical selection.
 * Passing an empty string removes the property from all selected text nodes.
 */
export const applyTextColor = (editor: LexicalEditor, color: string) => {
  editor.update(() => {
    const selection = $getSelection();
    if (selection !== null) {
      $patchStyleText(selection, { color: color || null });
    }
  });
};

/**
 * Applies an inline `background-color` CSS property to the current Lexical
 * selection.  Passing an empty string removes the property.
 */
export const applyBgColor = (editor: LexicalEditor, color: string) => {
  editor.update(() => {
    const selection = $getSelection();
    if (selection !== null) {
      $patchStyleText(selection, { "background-color": color || null });
    }
  });
};

import type {
