  top: 0,
};

export const DEFAULT_FORMAT_STATE: FloatingToolbarFormatState = {
  isBold: false,
  isCode: false,
  isHighlight: false,
  isItalic: false,
  isLink: false,
  isStrikethrough: false,
  isSubscript: false,
  isSuperscript: false,
  isUnderline: false,
  bgColor: "",
  textColor: "",
