"use client";

import { TOGGLE_LINK_COMMAND } from "@lexical/link";
import { useLexicalComposerContext } from "@lexical/react/LexicalComposerContext";
import { mergeRegister } from "@lexical/utils";
import { COMMAND_PRIORITY_LOW, SELECTION_CHANGE_COMMAND } from "lexical";
import {
  BaselineIcon,
  BoldIcon,
  CodeIcon,
  HighlighterIcon,
  ItalicIcon,
  LinkIcon,
  PaintBucketIcon,
  StrikethroughIcon,
  UnderlineIcon,
} from "lucide-react";
import { useCallback, useEffect, useRef, useState } from "react";
import { createPortal } from "react-dom";
import { Separator } from "@/components/ui/separator";
import { Toggle } from "@/components/ui/toggle";
import { cn } from "@/lib/utils";
import { ColorSwatches } from "../../ui/color-swatches";
import { LINK_PLACEHOLDER_URL } from "../link-behavior/utils";
import { applyBgColor, applyTextColor, toggleToolbarFormat } from "./actions";
import { DEFAULT_FORMAT_STATE, EMPTY_TOOLBAR_POSITION } from "./constants";
import { OPEN_FLOATING_LINK_EDITOR_COMMAND } from "./link-command";
import {
  areFloatingToolbarFormatsEqual,
  areFloatingToolbarPositionsEqual,
  readFloatingToolbarState,
} from "./selection";
import type {
  FloatingToolbarFormatState,
  FloatingToolbarPosition,
} from "./types";

const TOOLBAR_FORMAT_ACTIONS = [
  { format: "bold", icon: BoldIcon, key: "isBold" },
  { format: "italic", icon: ItalicIcon, key: "isItalic" },
  { format: "underline", icon: UnderlineIcon, key: "isUnderline" },
  { format: "strikethrough", icon: StrikethroughIcon, key: "isStrikethrough" },
  { format: "highlight", icon: HighlighterIcon, key: "isHighlight" },
  { format: "code", icon: CodeIcon, key: "isCode" },
] as const;

export function FloatingToolbarPlugin() {
  const [editor] = useLexicalComposerContext();
  const toolbarRef = useRef<HTMLDivElement>(null);

  const [isVisible, setIsVisible] = useState(false);
  const [position, setPosition] = useState<FloatingToolbarPosition>(
    EMPTY_TOOLBAR_POSITION
  );
  const [formats, setFormats] =
    useState<FloatingToolbarFormatState>(DEFAULT_FORMAT_STATE);
  const animationFrameRef = useRef<number | null>(null);

  /*
   * When a color picker popover is open we skip visibility/position updates so
   * the floating toolbar stays alive while the user browses swatches.  A ref
   * (rather than state) is used to avoid re-registering the update listener on
   * every open/close cycle.
   */
  const isColorPickerOpenRef = useRef(false);

  const updateToolbar = useCallback(() => {
    editor.getEditorState().read(() => {
      const toolbarState = readFloatingToolbarState();

      setFormats((currentFormats) => {
        return areFloatingToolbarFormatsEqual(
          currentFormats,
          toolbarState.formats
        )
          ? currentFormats
          : toolbarState.formats;
      });

      if (!isColorPickerOpenRef.current) {
        setIsVisible((currentIsVisible) => {
          return currentIsVisible === toolbarState.isVisible
            ? currentIsVisible
            : toolbarState.isVisible;
        });
        setPosition((currentPosition) => {
          return areFloatingToolbarPositionsEqual(
            currentPosition,
            toolbarState.position
          )
            ? currentPosition
            : toolbarState.position;
        });
      }
    });
  }, [editor]);

  const scheduleToolbarUpdate = useCallback(() => {
    if (animationFrameRef.current !== null) {
      return;
    }

    animationFrameRef.current = window.requestAnimationFrame(() => {
      animationFrameRef.current = null;
      updateToolbar();
    });
  }, [updateToolbar]);

  useEffect(() => {
    return mergeRegister(
      editor.registerCommand(
        SELECTION_CHANGE_COMMAND,
        () => {
          scheduleToolbarUpdate();
          return false;
        },
        COMMAND_PRIORITY_LOW
      ),
      editor.registerUpdateListener(() => {
        scheduleToolbarUpdate();
      })
    );
  }, [editor, scheduleToolbarUpdate]);

  useEffect(() => {
    return () => {
      if (animationFrameRef.current !== null) {
        window.cancelAnimationFrame(animationFrameRef.current);
      }
    };
  }, []);

  const handleLinkToggle = useCallback(() => {
    if (formats.isLink) {
      editor.dispatchCommand(TOGGLE_LINK_COMMAND, null);
      return;
    }

    editor.dispatchCommand(TOGGLE_LINK_COMMAND, LINK_PLACEHOLDER_URL);
    editor.dispatchCommand(OPEN_FLOATING_LINK_EDITOR_COMMAND, undefined);
  }, [editor, formats.isLink]);

  const handleColorPickerOpenChange = useCallback((open: boolean) => {
    isColorPickerOpenRef.current = open;
  }, []);

  if (!isVisible) {
    return null;
  }

  return createPortal(
    <div
      className="fixed z-50"
      ref={toolbarRef}
      style={{
        left: `${position.left}px`,
        top: `${position.top}px`,
        transform: "translate(-50%, -100%)",
      }}
    >
      <div
        aria-label="Formatting options"
        className={cn(
          "flex items-center gap-0.5 rounded-xl bg-popover p-1.5 shadow-lg ring-1 ring-border",
          "fade-in-0 zoom-in-95 animate-in duration-100"
        )}
        role="toolbar"
      >
        {TOOLBAR_FORMAT_ACTIONS.map((action) => {
          const Icon = action.icon;

          return (
            <Toggle
              key={action.format}
              onPressedChange={() => toggleToolbarFormat(editor, action.format)}
              pressed={formats[action.key]}
              size="sm"
            >
              <Icon />
            </Toggle>
          );
        })}

        <Separator className="mx-0.5 h-5" orientation="vertical" />

        {/* Text color — uses `color` CSS property */}
        <ColorSwatches
          activeColor={formats.textColor}
          icon={BaselineIcon}
          label="Text color"
          onColorChange={(color) => applyTextColor(editor, color)}
          onOpenChange={handleColorPickerOpenChange}
        />

        {/* Background color — uses `background-color` CSS property */}
        <ColorSwatches
          activeColor={formats.bgColor}
          icon={PaintBucketIcon}
          label="Background color"
          onColorChange={(color) => applyBgColor(editor, color)}
          onOpenChange={handleColorPickerOpenChange}
        />

        <Separator className="mx-0.5 h-5" orientation="vertical" />

        <Toggle
          onPressedChange={handleLinkToggle}
          pressed={formats.isLink}
          size="sm"
        >
          <LinkIcon />
        </Toggle>
      </div>
    </div>,
    document.body
  );
}

import { $isCodeNode } from "@lexical/code";
import { $isAutoLinkNode, $isLinkNode } from "@lexical/link";
import { $getSelectionStyleValueForProperty } from "@lexical/selection";
import {
  $getSelection,
  $isLineBreakNode,
  $isRangeSelection,
  type LexicalNode,
  type RangeSelection,
} from "lexical";
import { DEFAULT_FORMAT_STATE, EMPTY_TOOLBAR_POSITION } from "./constants";
import type {
  FloatingToolbarFormatState,
  FloatingToolbarPosition,
  FloatingToolbarState,
} from "./types";

export const areFloatingToolbarFormatsEqual = (
  left: FloatingToolbarFormatState,
  right: FloatingToolbarFormatState
) => {
  return (
    left.bgColor === right.bgColor &&
    left.isBold === right.isBold &&
    left.isCode === right.isCode &&
    left.isHighlight === right.isHighlight &&
    left.isItalic === right.isItalic &&
    left.isLink === right.isLink &&
    left.isStrikethrough === right.isStrikethrough &&
    left.isSubscript === right.isSubscript &&
    left.isSuperscript === right.isSuperscript &&
    left.isUnderline === right.isUnderline &&
    left.textColor === right.textColor
  );
};

export const areFloatingToolbarPositionsEqual = (
  left: FloatingToolbarPosition,
  right: FloatingToolbarPosition
) => {
  return left.left === right.left && left.top === right.top;
};

export const getFloatingToolbarSelectedNode = (selection: RangeSelection) => {
  const anchorNode = selection.anchor.getNode();
  const focusNode = selection.focus.getNode();

  if (anchorNode === focusNode) {
    return anchorNode;
  }

  return selection.isBackward() ? anchorNode : focusNode;
};

export const getSelectedLinkNode = (node: LexicalNode) => {
  const parent = node.getParent();

  if ($isLinkNode(parent) || $isAutoLinkNode(parent)) {
    return parent;
  }

  if ($isLinkNode(node) || $isAutoLinkNode(node)) {
    return node;
  }

  return null;
};

export const isSelectionWithinSingleLink = (selection: RangeSelection) => {
  const focusNode = getFloatingToolbarSelectedNode(selection);
  const focusLinkNode = getSelectedLinkNode(focusNode);

  if (!focusLinkNode) {
    return false;
  }

  const invalidNode = selection
    .getNodes()
    .filter((node) => !$isLineBreakNode(node))
    .find((node) => {
      const linkNode = getSelectedLinkNode(node);

      if (focusLinkNode && !focusLinkNode.is(linkNode)) {
        return true;
      }

      return $isAutoLinkNode(linkNode) && linkNode.getIsUnlinked();
    });

  return invalidNode === undefined;
};

const getToolbarPosition = (): FloatingToolbarPosition | null => {
  const nativeSelection = window.getSelection();
  if (!(nativeSelection && nativeSelection.rangeCount > 0)) {
    return null;
  }

  const range = nativeSelection.getRangeAt(0);
  const rectangle = range.getBoundingClientRect();

  if (rectangle.width === 0 && rectangle.height === 0) {
    return null;
  }

  return {
    left: rectangle.left + rectangle.width / 2,
    top: rectangle.top - 10,
  };
};

const getFormatState = (
  selection: RangeSelection,
  node: LexicalNode
): FloatingToolbarFormatState => {
  const linkNode = getSelectedLinkNode(node);

  return {
    isBold: selection.hasFormat("bold"),
    isCode: selection.hasFormat("code"),
    isHighlight: selection.hasFormat("highlight"),
    isItalic: selection.hasFormat("italic"),
    isLink: linkNode !== null,
    isStrikethrough: selection.hasFormat("strikethrough"),
    isSubscript: selection.hasFormat("subscript"),
    isSuperscript: selection.hasFormat("superscript"),
    isUnderline: selection.hasFormat("underline"),
    bgColor: $getSelectionStyleValueForProperty(
      selection,
      "background-color",
      ""
    ),
    textColor: $getSelectionStyleValueForProperty(selection, "color", ""),
  };
};

/**
 * Reads inline format state at the current cursor or selection without any
 * visibility or position checks. Intended for static (non-floating) toolbars
 * that always need to reflect the current editor state.
 */
export const readInlineFormats = (): FloatingToolbarFormatState => {
  const selection = $getSelection();
  if (!$isRangeSelection(selection)) {
    return DEFAULT_FORMAT_STATE;
  }

  const node = getFloatingToolbarSelectedNode(selection);
  return getFormatState(selection, node);
};

export const readFloatingToolbarState = (): FloatingToolbarState => {
  const selection = $getSelection();
  if (!($isRangeSelection(selection) && !selection.isCollapsed())) {
    return {
      formats: DEFAULT_FORMAT_STATE,
      isVisible: false,
      linkUrl: "",
      position: EMPTY_TOOLBAR_POSITION,
    };
  }

  const node = getFloatingToolbarSelectedNode(selection);
  const parent = node.getParent();
  const isInsideCodeBlock =
    $isCodeNode(node) || (parent && $isCodeNode(parent));

  if (isInsideCodeBlock) {
    return {
      formats: DEFAULT_FORMAT_STATE,
      isVisible: false,
      linkUrl: "",
      position: EMPTY_TOOLBAR_POSITION,
    };
  }

  const position = getToolbarPosition();
  if (!position) {
    return {
      formats: DEFAULT_FORMAT_STATE,
      isVisible: false,
      linkUrl: "",
      position: EMPTY_TOOLBAR_POSITION,
    };
  }

  const linkNode = isSelectionWithinSingleLink(selection)
    ? getSelectedLinkNode(node)
    : null;

  return {
    formats: getFormatState(selection, node),
    isVisible: true,
    linkUrl: linkNode?.getURL() ?? "",
    position,
  };
};

export interface FloatingToolbarFormatState {
  /** Current background-color CSS value of the selection, or "" if none/mixed. */
  bgColor: string;
  isBold: boolean;
  isCode: boolean;
  isHighlight: boolean;
  isItalic: boolean;
  isLink: boolean;
  isStrikethrough: boolean;
  isSubscript: boolean;
  isSuperscript: boolean;
  isUnderline: boolean;
  /** Current color CSS value of the selection, or "" if none/mixed. */
  textColor: string;
}

export interface FloatingToolbarPosition {
  left: number;
  top: number;
}

export interface FloatingToolbarState {
  formats: FloatingToolbarFormatState;
  isVisible: boolean;
  linkUrl: string;
  position: FloatingToolbarPosition;
}

