  StrikethroughIcon,
  SubscriptIcon,
  SuperscriptIcon,
  TableIcon,
  UnderlineIcon,
  UndoIcon,
} from "lucide-react";
import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { Button } from "@/components/ui/button";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import { Separator } from "@/components/ui/separator";
import { Toggle } from "@/components/ui/toggle";
import { cn } from "@/lib/utils";
import { ColorSwatches } from "../../ui/color-swatches";
import {
  BLOCK_ICONS,
  BLOCK_LABELS,
  BLOCK_OPTIONS,
} from "../block-type-toolbar/options";
import type { BlockTypeValue } from "../block-type-toolbar/types";
import {
  applyBlockType,
  getBlockTypeFromSelection,
  getCurrentBlockOption,
} from "../block-type-toolbar/utils";
import { INSERT_COLLAPSIBLE_COMMAND } from "../collapsible/commands";
import {
  applyBgColor,
  applyTextColor,
  toggleToolbarFormat,
} from "../floating-toolbar/actions";
import { DEFAULT_FORMAT_STATE } from "../floating-toolbar/constants";
import { OPEN_FLOATING_LINK_EDITOR_COMMAND } from "../floating-toolbar/link-command";
import {
  areFloatingToolbarFormatsEqual,
  readInlineFormats,
} from "../floating-toolbar/selection";
import type { FloatingToolbarFormatState } from "../floating-toolbar/types";
import { LINK_PLACEHOLDER_URL } from "../link-behavior/utils";
import { DEFAULT_INSERT_TABLE_PAYLOAD } from "../table-behavior/constants";

/** Short abbreviations shown in the block-type pill. */
const BLOCK_ABBR: Record<BlockTypeValue, string> = {
  bullet: "•",
  check: "□",
  code: "<>",
  h1: "H1",
  h2: "H2",
  h3: "H3",
  number: "1.",
  paragraph: "P",
  quote: "❝",
  table: "⊞",
};

const INLINE_FORMAT_ACTIONS = [
  { format: "bold", icon: BoldIcon, key: "isBold", label: "Bold" },
  { format: "italic", icon: ItalicIcon, key: "isItalic", label: "Italic" },
  {
    format: "strikethrough",
    icon: StrikethroughIcon,
    key: "isStrikethrough",
    label: "Strikethrough",
  },
  { format: "code", icon: CodeIcon, key: "isCode", label: "Inline code" },
  {
    format: "underline",
    icon: UnderlineIcon,
    key: "isUnderline",
    label: "Underline",
  },
  {
    format: "highlight",
    icon: HighlighterIcon,
    key: "isHighlight",
    label: "Highlight",
  },
] as const;

const ALIGN_ACTIONS = [
  { align: "left" as const, icon: AlignLeftIcon, label: "Align left" },
  { align: "center" as const, icon: AlignCenterIcon, label: "Align center" },
  { align: "right" as const, icon: AlignRightIcon, label: "Align right" },
  { align: "justify" as const, icon: AlignJustifyIcon, label: "Justify" },
];

interface FullToolbarPluginProps {
  className?: string;
}

export function FullToolbarPlugin({ className }: FullToolbarPluginProps) {
  const [editor] = useLexicalComposerContext();

  const [blockType, setBlockType] = useState<BlockTypeValue>("paragraph");
  const [blockTypeOpen, setBlockTypeOpen] = useState(false);
  const [activeBlockTypeIndex, setActiveBlockTypeIndex] = useState(0);
  const [insertOpen, setInsertOpen] = useState(false);
  const [activeInsertIndex, setActiveInsertIndex] = useState(0);
  const [formats, setFormats] =
    useState<FloatingToolbarFormatState>(DEFAULT_FORMAT_STATE);
  const blockTypeOptionRefs = useRef<Array<HTMLButtonElement | null>>([]);
  const insertOptionRefs = useRef<Array<HTMLButtonElement | null>>([]);

  const currentOption = useMemo(
    () => getCurrentBlockOption(blockType, BLOCK_OPTIONS),
    [blockType]
  );

  const update = useCallback(() => {
    editor.getEditorState().read(() => {
      const nextBlockType = getBlockTypeFromSelection();
      const resolvedBlockType = nextBlockType ?? "paragraph";

      setBlockType((currentBlockType) => {
        return currentBlockType === resolvedBlockType
          ? currentBlockType
          : resolvedBlockType;
      });

      const nextFormats = readInlineFormats();
      setFormats((currentFormats) => {
        return areFloatingToolbarFormatsEqual(currentFormats, nextFormats)
          ? currentFormats
          : nextFormats;
      });
    });
  }, [editor]);

  useEffect(() => {
    return mergeRegister(
      editor.registerCommand(
        SELECTION_CHANGE_COMMAND,
        () => {
          update();
          return false;
        },
        COMMAND_PRIORITY_LOW
      ),
      editor.registerUpdateListener(() => {
        update();
      })
    );
  }, [editor, update]);

  const handleBlockTypeChange = useCallback(
    (value: BlockTypeValue) => {
      applyBlockType(editor, value);
      setBlockType(value);
      setBlockTypeOpen(false);
    },
    [editor]
  );

  const handleBlockTypeOpenChange = useCallback(
    (open: boolean) => {
      if (open) {
        const initialIndex = Math.max(
          BLOCK_OPTIONS.findIndex((option) => option.value === blockType),
          0
        );

        setActiveBlockTypeIndex(initialIndex);
      }

      setBlockTypeOpen(open);
    },
    [blockType]
  );

  const handleInsertOpenChange = useCallback((open: boolean) => {
    if (open) {
      setActiveInsertIndex(0);
    }

    setInsertOpen(open);
  }, []);

  const focusBlockTypeOption = useCallback((index: number) => {
    const optionCount = BLOCK_OPTIONS.length;
    const nextIndex = (index + optionCount) % optionCount;

    setActiveBlockTypeIndex(nextIndex);
    blockTypeOptionRefs.current[nextIndex]?.focus();
  }, []);

  useEffect(() => {
    if (!blockTypeOpen) {
      return;
    }

    const animationFrameId = requestAnimationFrame(() => {
      blockTypeOptionRefs.current[activeBlockTypeIndex]?.focus();
    });

    return () => {
      cancelAnimationFrame(animationFrameId);
    };
  }, [activeBlockTypeIndex, blockTypeOpen]);

  useEffect(() => {
    if (!insertOpen) {
      return;
    }

    const animationFrameId = requestAnimationFrame(() => {
      insertOptionRefs.current[activeInsertIndex]?.focus();
    });

    return () => {
      cancelAnimationFrame(animationFrameId);
    };
  }, [activeInsertIndex, insertOpen]);

  const handleBlockTypeListKeyDown = useCallback(
    (event: React.KeyboardEvent<HTMLDivElement>) => {
      switch (event.key) {
        case "ArrowDown": {
          event.preventDefault();
          focusBlockTypeOption(activeBlockTypeIndex + 1);
          return;
        }
        case "ArrowUp": {
          event.preventDefault();
          focusBlockTypeOption(activeBlockTypeIndex - 1);
          return;
        }
        case "Home": {
          event.preventDefault();
          focusBlockTypeOption(0);
          return;
        }
        case "End": {
          event.preventDefault();
          focusBlockTypeOption(BLOCK_OPTIONS.length - 1);
          return;
        }
        case "Enter":
        case " ": {
          event.preventDefault();
          handleBlockTypeChange(BLOCK_OPTIONS[activeBlockTypeIndex].value);
          return;
        }
        default: {
          return;
        }
      }
    },
    [activeBlockTypeIndex, focusBlockTypeOption, handleBlockTypeChange]
  );

  const handleLinkToggle = useCallback(() => {
    if (formats.isLink) {
      editor.dispatchCommand(TOGGLE_LINK_COMMAND, null);
      return;
    }
    editor.dispatchCommand(TOGGLE_LINK_COMMAND, LINK_PLACEHOLDER_URL);
    editor.dispatchCommand(OPEN_FLOATING_LINK_EDITOR_COMMAND, undefined);
  }, [editor, formats.isLink]);

  const insertTable = useCallback(() => {
    editor.dispatchCommand(INSERT_TABLE_COMMAND, DEFAULT_INSERT_TABLE_PAYLOAD);
    setInsertOpen(false);
  }, [editor]);

  const insertDivider = useCallback(() => {
    editor.dispatchCommand(INSERT_HORIZONTAL_RULE_COMMAND, undefined);
    setInsertOpen(false);
  }, [editor]);

  const insertCollapsible = useCallback(() => {
    editor.dispatchCommand(INSERT_COLLAPSIBLE_COMMAND, undefined);
    setInsertOpen(false);
  }, [editor]);

  const insertActions = useMemo(
    () => [
      {
        icon: <TableIcon className="size-4 text-muted-foreground" />,
        label: "Table",
        onSelect: insertTable,
      },
      {
        icon: (
          <span className="flex size-4 items-center justify-center text-muted-foreground">
            -
          </span>
        ),
        label: "Divider",
        onSelect: insertDivider,
      },
      {
        icon: <ChevronDownIcon className="size-4 text-muted-foreground" />,
        label: "Collapsible",
        onSelect: insertCollapsible,
      },
    ],
    [insertCollapsible, insertDivider, insertTable]
  );

  const focusInsertOption = useCallback(
    (index: number) => {
      const optionCount = insertActions.length;
      const nextIndex = (index + optionCount) % optionCount;

      setActiveInsertIndex(nextIndex);
      insertOptionRefs.current[nextIndex]?.focus();
    },
    [insertActions.length]
  );

  const handleInsertListKeyDown = useCallback(
    (event: React.KeyboardEvent<HTMLDivElement>) => {
      switch (event.key) {
        case "ArrowDown": {
          event.preventDefault();
          focusInsertOption(activeInsertIndex + 1);
          return;
        }
        case "ArrowUp": {
          event.preventDefault();
          focusInsertOption(activeInsertIndex - 1);
          return;
        }
        case "Home": {
          event.preventDefault();
          focusInsertOption(0);
          return;
        }
        case "End": {
          event.preventDefault();
          focusInsertOption(insertActions.length - 1);
          return;
        }
        case "Enter":
        case " ": {
          event.preventDefault();
          insertActions[activeInsertIndex]?.onSelect();
          return;
        }
        default: {
          return;
        }
      }
    },
    [activeInsertIndex, focusInsertOption, insertActions]
  );

  const abbr = BLOCK_ABBR[blockType] ?? "P";
  const isParagraph = blockType === "paragraph";

  return (
    <div
      aria-label="Formatting toolbar"
      className={cn("flex flex-wrap items-center gap-0.5", className)}
      role="toolbar"
    >
      {/* Undo / Redo */}
      <Button
        aria-label="Undo"
        onClick={() => editor.dispatchCommand(UNDO_COMMAND, undefined)}
        size="icon-sm"
        type="button"
        variant="ghost"
      >
        <UndoIcon />
      </Button>
      <Button
        aria-label="Redo"
        onClick={() => editor.dispatchCommand(REDO_COMMAND, undefined)}
        size="icon-sm"
        type="button"
        variant="ghost"
      >
        <RedoIcon />
      </Button>

      <Separator className="mx-0.5 h-4" orientation="vertical" />

      {/* Block type pill */}
      <Popover onOpenChange={handleBlockTypeOpenChange} open={blockTypeOpen}>
        <PopoverTrigger
          render={
            <Button
              aria-label={`Block type: ${currentOption?.label ?? BLOCK_LABELS.paragraph}`}
              className={cn(
                "h-7 gap-1 rounded-full px-2 font-semibold text-xs",
                isParagraph
                  ? "variant-ghost"
                  : "bg-primary/10 text-primary hover:bg-primary/15"
              )}
              size="sm"
              type="button"
              variant={isParagraph ? "ghost" : "ghost"}
            />
          }
        >
          <span className="min-w-[1.5ch] text-center">{abbr}</span>
          <ChevronDownIcon className="size-3 shrink-0 text-muted-foreground" />
        </PopoverTrigger>
        <PopoverContent align="start" className="w-72 p-1">
          <div
            className="space-y-0.5"
            onKeyDown={handleBlockTypeListKeyDown}
            role="listbox"
          >
            {BLOCK_OPTIONS.map((option, optionIndex) => {
              const Icon = BLOCK_ICONS[option.value];
              const isSelected = option.value === blockType;
              const isActive = optionIndex === activeBlockTypeIndex;

              return (
                <button
                  aria-selected={isSelected}
                  className={cn(
                    "flex w-full items-start gap-3 rounded-md px-3 py-2 text-left transition-colors hover:bg-accent focus-visible:bg-accent focus-visible:outline-none",
                    isActive && "bg-accent"
                  )}
                  key={option.value}
                  onClick={() => handleBlockTypeChange(option.value)}
                  onFocus={() => setActiveBlockTypeIndex(optionIndex)}
                  onMouseEnter={() => setActiveBlockTypeIndex(optionIndex)}
                  ref={(element) => {
                    blockTypeOptionRefs.current[optionIndex] = element;
                  }}
                  role="option"
                  tabIndex={optionIndex === activeBlockTypeIndex ? 0 : -1}
                  type="button"
                >
                  <span className="mt-0.5 rounded-sm bg-muted p-1 text-muted-foreground">
                    <Icon className="size-4" />
                  </span>
                  <span className="flex flex-col">
                    <span className="font-medium text-foreground text-sm">
                      {option.label}
                    </span>
                    <span className="text-muted-foreground text-xs">
                      {option.description}
                    </span>
                  </span>
                  {isSelected && (
                    <CheckIcon className="ml-auto size-3.5 shrink-0 self-center text-muted-foreground" />
                  )}
                </button>
              );
            })}
          </div>
        </PopoverContent>
      </Popover>

      <Separator className="mx-0.5 h-4" orientation="vertical" />

      {/* Inline format toggles */}
      {INLINE_FORMAT_ACTIONS.map((action) => {
        const Icon = action.icon;

        return (
          <Toggle
            aria-label={action.label}
            key={action.format}
            onPressedChange={() => toggleToolbarFormat(editor, action.format)}
            pressed={formats[action.key]}
            size="sm"
          >
            <Icon />
          </Toggle>
        );
      })}

      {/* Text color / background color */}
      <ColorSwatches
        activeColor={formats.textColor}
        icon={BaselineIcon}
        label="Text color"
        onColorChange={(color) => applyTextColor(editor, color)}
      />
      <ColorSwatches
        activeColor={formats.bgColor}
        icon={PaintBucketIcon}
        label="Background color"
        onColorChange={(color) => applyBgColor(editor, color)}
      />

      {/* Link */}
      <Toggle
        aria-label="Link"
        onPressedChange={handleLinkToggle}
        pressed={formats.isLink}
        size="sm"
      >
        <LinkIcon />
      </Toggle>

      <Separator className="mx-0.5 h-4" orientation="vertical" />

      {/* Superscript / Subscript */}
      <Toggle
        aria-label="Superscript"
        onPressedChange={() =>
          editor.dispatchCommand(FORMAT_TEXT_COMMAND, "superscript")
        }
        pressed={formats.isSuperscript}
        size="sm"
      >
        <SuperscriptIcon />
      </Toggle>
      <Toggle
        aria-label="Subscript"
        onPressedChange={() =>
          editor.dispatchCommand(FORMAT_TEXT_COMMAND, "subscript")
        }
        pressed={formats.isSubscript}
        size="sm"
      >
        <SubscriptIcon />
      </Toggle>

      <Separator className="mx-0.5 h-4" orientation="vertical" />

      {/* Alignment */}
      {ALIGN_ACTIONS.map((action) => {
        const Icon = action.icon;

        return (
          <Button
            aria-label={action.label}
            key={action.align}
            onClick={() =>
              editor.dispatchCommand(FORMAT_ELEMENT_COMMAND, action.align)
            }
            size="icon-sm"
            type="button"
            variant="ghost"
          >
            <Icon />
          </Button>
        );
      })}

      <Separator className="mx-0.5 h-4" orientation="vertical" />

      {/* Indent / Outdent */}
      <Button
        aria-label="Outdent"
        onClick={() =>
          editor.dispatchCommand(OUTDENT_CONTENT_COMMAND, undefined)
        }
        size="icon-sm"
        type="button"
        variant="ghost"
      >
        <IndentDecreaseIcon />
      </Button>
      <Button
        aria-label="Indent"
        onClick={() =>
          editor.dispatchCommand(INDENT_CONTENT_COMMAND, undefined)
        }
        size="icon-sm"
        type="button"
        variant="ghost"
      >
        <IndentIncreaseIcon />
      </Button>

      <Separator className="mx-0.5 h-4" orientation="vertical" />

      {/* Insert popover */}
      <Popover onOpenChange={handleInsertOpenChange} open={insertOpen}>
        <PopoverTrigger
          render={
            <Button
              aria-label="Insert"
              className="h-7 gap-1.5 rounded-full px-2.5 text-xs"
              size="sm"
              type="button"
              variant="ghost"
            />
          }
        >
          <PlusIcon className="size-3.5" />
          <span>Insert</span>
        </PopoverTrigger>
        <PopoverContent align="start" className="w-44 p-1">
          <div
            className="space-y-0.5"
            onKeyDown={handleInsertListKeyDown}
            role="listbox"
          >
            {insertActions.map((action, optionIndex) => {
              const isActive = optionIndex === activeInsertIndex;

              return (
                <button
                  className={cn(
                    "flex w-full items-center gap-2 rounded-md px-3 py-2 text-left text-sm transition-colors hover:bg-accent focus-visible:bg-accent focus-visible:outline-none",
                    isActive && "bg-accent"
                  )}
                  key={action.label}
                  onClick={action.onSelect}
                  onFocus={() => setActiveInsertIndex(optionIndex)}
                  onMouseEnter={() => setActiveInsertIndex(optionIndex)}
                  ref={(element) => {
                    insertOptionRefs.current[optionIndex] = element;
                  }}
                  role="option"
                  tabIndex={optionIndex === activeInsertIndex ? 0 : -1}
                  type="button"
                >
                  {action.icon}
                  {action.label}
                </button>
              );
            })}
          </div>
        </PopoverContent>
      </Popover>
    </div>
  );
}

import type { NodeKey } from "lexical";
import { createCommand } from "lexical";
import type { ImageAlignment } from "../../core/nodes/image/node";

export interface InsertImagePayload {
  alignment?: ImageAlignment;
  altText: string;
  src: string;
  targetNodeKey?: NodeKey;
}

export const INSERT_IMAGE_COMMAND = createCommand<InsertImagePayload>(
  "INSERT_IMAGE_COMMAND"
);

"use client";

import { useLexicalComposerContext } from "@lexical/react/LexicalComposerContext";
import { useLexicalEditable } from "@lexical/react/useLexicalEditable";
import { useLexicalNodeSelection } from "@lexical/react/useLexicalNodeSelection";
import { mergeRegister } from "@lexical/utils";
import {
  $getNodeByKey,
  $getSelection,
  $isNodeSelection,
  CLICK_COMMAND,
  COMMAND_PRIORITY_LOW,
  DRAGSTART_COMMAND,
  FORMAT_ELEMENT_COMMAND,
  KEY_BACKSPACE_COMMAND,
  KEY_DELETE_COMMAND,
  type NodeKey,
} from "lexical";
import { useEffect, useMemo, useRef, useState } from "react";
import { $isImageNode, type ImageAlignment } from "../../core/nodes/image/node";
import { ImageResizer } from "./resizer";

interface ImageComponentProps {
  alignment: ImageAlignment;
  altText: string;
  height: number | "inherit";
  nodeKey: NodeKey;
  src: string;
  width: number | "inherit";
}

const DEFAULT_IMAGE_WIDTH = 640;

export function ImageComponent({
  alignment,
  altText,
  height,
  nodeKey,
  src,
  width,
}: ImageComponentProps) {
  const [editor] = useLexicalComposerContext();
  const editable = useLexicalEditable();
  const [isSelected, setSelected, clearSelection] =
    useLexicalNodeSelection(nodeKey);
  const imageRef = useRef<HTMLImageElement | null>(null);
  const [isResizing, setIsResizing] = useState(false);
  const effectiveWidth = width === "inherit" ? DEFAULT_IMAGE_WIDTH : width;
  const isInNodeSelection = useMemo(() => {
    if (!isSelected) {
      return false;
    }

    return editor.getEditorState().read(() => {
      const selection = $getSelection();
      return $isNodeSelection(selection) && selection.has(nodeKey);
    });
  }, [editor, isSelected, nodeKey]);
  const isFocused = (isSelected || isResizing) && editable;
  let figureClassName = "my-4 w-fit max-w-full";
  let alignmentClassName = "inline-flex max-w-full";

  if (alignment === "center") {
    figureClassName = "my-4 w-full";
    alignmentClassName = "flex max-w-full justify-center";
  } else if (alignment === "right") {
    figureClassName = "my-4 ml-auto w-fit max-w-full";
    alignmentClassName = "flex max-w-full justify-end";
  }

  useEffect(() => {
    if (!editable) {
      return;
    }

    const removeSelectedImage = (event: KeyboardEvent) => {
      const selection = $getSelection();
      if (!(isSelected && $isNodeSelection(selection))) {
        return false;
      }

      event.preventDefault();

      editor.update(() => {
        const node = $getNodeByKey(nodeKey);
        if ($isImageNode(node)) {
          node.remove();
        }
      });

      return true;
    };

    return mergeRegister(
      editor.registerCommand(
        CLICK_COMMAND,
        (event) => {
          if (isResizing) {
            return true;
          }

          if (event.target !== imageRef.current) {
            return false;
          }

          if (event.shiftKey) {
            setSelected(!isSelected);
          } else {
            clearSelection();
            setSelected(true);
          }

          return true;
        },
        COMMAND_PRIORITY_LOW
      ),
      editor.registerCommand(
        DRAGSTART_COMMAND,
        (event) => {
          if (event.target === imageRef.current) {
            event.preventDefault();
            return true;
          }

          return false;
        },
        COMMAND_PRIORITY_LOW
      ),
      editor.registerCommand(
        FORMAT_ELEMENT_COMMAND,
        (format) => {
          if (!isSelected) {
            return false;
          }

          if (
            !(format === "left" || format === "center" || format === "right")
          ) {
            return false;
          }

          editor.update(() => {
            const node = $getNodeByKey(nodeKey);
            if ($isImageNode(node)) {
              node.setAlignment(format as ImageAlignment);
            }
          });

          return true;
        },
        COMMAND_PRIORITY_LOW
      ),
      editor.registerCommand(
        KEY_BACKSPACE_COMMAND,
        removeSelectedImage,
        COMMAND_PRIORITY_LOW
      ),
      editor.registerCommand(
        KEY_DELETE_COMMAND,
        removeSelectedImage,
        COMMAND_PRIORITY_LOW
      )
    );
  }, [
    clearSelection,
    editable,
    editor,
    isResizing,
    isSelected,
    nodeKey,
    setSelected,
  ]);

  useEffect(() => {
    return () => {
      document.body.style.removeProperty("cursor");
      document.body.style.removeProperty("-webkit-user-select");
      document.body.style.removeProperty("user-select");
    };
  }, []);

  return (
    <figure className={figureClassName}>
      <div className={alignmentClassName}>
        <div className="relative inline-flex max-w-full">
          <div
            className={
              isFocused
                ? "rounded-2xl ring-1 ring-primary/40 ring-offset-2 ring-offset-background"
                : "rounded-2xl"
            }
          >
            <img
              alt={altText}
              className="block h-auto max-w-full rounded-xl border border-border/60 bg-muted/20 shadow-xs"
              draggable="false"
              height={height === "inherit" ? undefined : height}
              ref={imageRef}
              src={src}
              width={effectiveWidth}
            />
          </div>

          {editable && isInNodeSelection && isFocused ? (
            <ImageResizer
              editor={editor}
              imageRef={imageRef}
              onResizeEnd={(nextWidth, nextHeight) => {
                window.setTimeout(() => {
                  setIsResizing(false);
                }, 200);

                editor.update(() => {
                  const node = $getNodeByKey(nodeKey);
                  if ($isImageNode(node)) {
                    node.setWidthAndHeight(nextWidth, nextHeight);
                  }
                });
              }}
              onResizeStart={() => {
                setIsResizing(true);
              }}
            />
          ) : null}
        </div>
      </div>
    </figure>
  );
}

"use client";

import { useLexicalComposerContext } from "@lexical/react/LexicalComposerContext";
import { DRAG_DROP_PASTE, eventFiles } from "@lexical/rich-text";
import {
  $createParagraphNode,
  $getNodeByKey,
  $getSelection,
  $insertNodes,
  $isElementNode,
  $isRangeSelection,
  COMMAND_PRIORITY_EDITOR,
  COMMAND_PRIORITY_HIGH,
  DROP_COMMAND,
  PASTE_COMMAND,
} from "lexical";
import { useEffect } from "react";
import { $createImageNode, $isImageNode } from "../../core/nodes/image/node";
import { INSERT_IMAGE_COMMAND } from "./commands";
import { getFirstImageFile, readFileAsDataUrl } from "./utils";

const insertParagraphAfterImage = (
  imageNode: ReturnType<typeof $createImageNode>
) => {
  if (!$isImageNode(imageNode)) {
    return;
  }

  const paragraph = $createParagraphNode();
  imageNode.insertAfter(paragraph);
  paragraph.select();
};

export function ImagePlugin() {
  const [editor] = useLexicalComposerContext();

  useEffect(() => {
    const insertImage = ({
      alignment,
      altText,
      src,
      targetNodeKey,
    }: {
      alignment?: "left" | "center" | "right";
      altText: string;
      src: string;
      targetNodeKey?: string;
    }) => {
      const trimmedSrc = src.trim();
      if (!trimmedSrc) {
        return false;
      }

      const imageNode = $createImageNode({
        alignment,
        altText: altText.trim(),
        src: trimmedSrc,
      });

      if (targetNodeKey) {
        const targetNode = $getNodeByKey(targetNodeKey);
        if (!$isElementNode(targetNode)) {
          return false;
        }

        targetNode.replace(imageNode);
        insertParagraphAfterImage(imageNode);
        return true;
      }

      const selection = $getSelection();
      if (!$isRangeSelection(selection)) {
        return false;
      }

      $insertNodes([imageNode]);
      insertParagraphAfterImage(imageNode);
      return true;
    };

    return editor.registerCommand(
      INSERT_IMAGE_COMMAND,
      (payload) => insertImage(payload),
      COMMAND_PRIORITY_EDITOR
    );
  }, [editor]);

  useEffect(() => {
    const insertImageFile = async (file: File) => {
      const src = await readFileAsDataUrl(file);

      editor.update(() => {
        editor.dispatchCommand(INSERT_IMAGE_COMMAND, {
          altText: file.name,
          src,
        });
      });
    };

    return editor.registerCommand(
      DRAG_DROP_PASTE,
      (files) => {
        const imageFile = getFirstImageFile(files);
        if (!imageFile) {
          return false;
        }

        insertImageFile(imageFile).catch(() => undefined);
        return true;
      },
      COMMAND_PRIORITY_HIGH
    );
  }, [editor]);

  useEffect(() => {
    return editor.registerCommand(
      PASTE_COMMAND,
      (event) => {
        const [, files] = eventFiles(event);
        const imageFile = getFirstImageFile(files);
        if (!imageFile) {
          return false;
        }

        event.preventDefault();
        editor.dispatchCommand(DRAG_DROP_PASTE, [imageFile]);
        return true;
      },
      COMMAND_PRIORITY_HIGH
    );
  }, [editor]);

  useEffect(() => {
    return editor.registerCommand(
      DROP_COMMAND,
      (event) => {
        const [, files] = eventFiles(event);
        const imageFile = getFirstImageFile(files);
        if (!imageFile) {
          return false;
        }

        event.preventDefault();
        editor.dispatchCommand(DRAG_DROP_PASTE, [imageFile]);
        return true;
      },
      COMMAND_PRIORITY_HIGH
    );
  }, [editor]);

  return null;
}

"use client";

import { calculateZoomLevel } from "@lexical/utils";
import type { LexicalEditor } from "lexical";
import { useRef } from "react";

type ResizeDirection = "ne" | "nw" | "se" | "sw";

interface ImageResizerProps {
  editor: LexicalEditor;
  imageRef: { current: HTMLImageElement | null };
  maxWidth?: number;
  onResizeEnd: (width: number, height: number) => void;
  onResizeStart: () => void;
}

interface ResizeState {
  currentHeight: number;
  currentWidth: number;
  direction: ResizeDirection;
  isResizing: boolean;
  ratio: number;
  startHeight: number;
  startWidth: number;
  startX: number;
  startY: number;
}

const CORNER_DIRECTIONS: ResizeDirection[] = ["ne", "se", "sw", "nw"];

const CORNER_CLASSES: Record<ResizeDirection, string> = {
  ne: "right-0 top-0 translate-x-1/2 -translate-y-1/2 cursor-nesw-resize",
  se: "bottom-0 right-0 translate-x-1/2 translate-y-1/2 cursor-nwse-resize",
  sw: "bottom-0 left-0 -translate-x-1/2 translate-y-1/2 cursor-nesw-resize",
  nw: "left-0 top-0 -translate-x-1/2 -translate-y-1/2 cursor-nwse-resize",
};

const clamp = (value: number, min: number, max: number) =>
  Math.min(Math.max(value, min), max);

const isEast = (d: ResizeDirection) => d === "ne" || d === "se";

const getCursor = (d: ResizeDirection) =>
  d === "nw" || d === "se" ? "nwse-resize" : "nesw-resize";

export function ImageResizer({
  editor,
  imageRef,
  maxWidth,
  onResizeEnd,
  onResizeStart,
}: ImageResizerProps) {
  const controlWrapperRef = useRef<HTMLDivElement | null>(null);
  const userSelect = useRef({ priority: "", value: "default" });
  const positioningRef = useRef<ResizeState>({
    currentHeight: 0,
    currentWidth: 0,
    direction: "se",
    isResizing: false,
    ratio: 0,
    startHeight: 0,
    startWidth: 0,
    startX: 0,
    startY: 0,
  });

  const editorRootElement = editor.getRootElement();
  let maxWidthContainer = 100;
  if (maxWidth) {
    maxWidthContainer = maxWidth;
  } else if (editorRootElement) {
    maxWidthContainer = editorRootElement.getBoundingClientRect().width - 20;
  }

  const setStartCursor = (direction: ResizeDirection) => {
    const cursor = getCursor(direction);
    editorRootElement?.style.setProperty("cursor", cursor, "important");
    document.body.style.setProperty("cursor", cursor, "important");
    userSelect.current.value = document.body.style.getPropertyValue(
      "-webkit-user-select"
    );
    userSelect.current.priority = document.body.style.getPropertyPriority(
      "-webkit-user-select"
    );
    document.body.style.setProperty("-webkit-user-select", "none", "important");
  };

  const setEndCursor = () => {
    editorRootElement?.style.setProperty("cursor", "text");
    document.body.style.setProperty("cursor", "default");
    document.body.style.setProperty(
      "-webkit-user-select",
      userSelect.current.value,
      userSelect.current.priority
    );
  };

  const handlePointerMove = (event: PointerEvent) => {
    const image = imageRef.current;
    const positioning = positioningRef.current;

    if (!(image && positioning.isResizing)) {
      return;
    }

    const zoom = calculateZoomLevel(image);
    // All corners resize both axes while locking aspect ratio.
    let diff = Math.floor(positioning.startX - event.clientX / zoom);
    diff = isEast(positioning.direction) ? -diff : diff;

    const width = clamp(positioning.startWidth + diff, 100, maxWidthContainer);
    const height = width / positioning.ratio;

    image.style.width = `${width}px`;
    image.style.height = `${height}px`;
    positioning.currentHeight = height;
    positioning.currentWidth = width;
  };

  const handlePointerUp = () => {
    const image = imageRef.current;
    const controlWrapper = controlWrapperRef.current;
    const positioning = positioningRef.current;

    document.removeEventListener("pointermove", handlePointerMove);
    document.removeEventListener("pointerup", handlePointerUp);
    setEndCursor();

    if (!(image && controlWrapper && positioning.isResizing)) {
      return;
    }

    const width = positioning.currentWidth;
    const height = positioning.currentHeight;

    positioning.startWidth = 0;
    positioning.startHeight = 0;
    positioning.ratio = 0;
    positioning.startX = 0;
    positioning.startY = 0;
    positioning.currentWidth = 0;
    positioning.currentHeight = 0;
    positioning.isResizing = false;

    controlWrapper.classList.remove("image-control-wrapper--resizing");
    onResizeEnd(width, height);
  };

  const handlePointerDown = (
    event: React.PointerEvent<HTMLDivElement>,
    direction: ResizeDirection
  ) => {
    if (!editor.isEditable()) {
      return;
    }

    const image = imageRef.current;
    const controlWrapper = controlWrapperRef.current;

    if (!(image && controlWrapper)) {
      return;
    }

    event.preventDefault();

    const { height, width } = image.getBoundingClientRect();
    const zoom = calculateZoomLevel(image);
    const positioning = positioningRef.current;

    positioning.startWidth = width;
    positioning.startHeight = height;
    positioning.ratio = width / height;
    positioning.currentWidth = width;
    positioning.currentHeight = height;
    positioning.startX = event.clientX / zoom;
    positioning.startY = event.clientY / zoom;
    positioning.isResizing = true;
    positioning.direction = direction;

    setStartCursor(direction);
    onResizeStart();

    controlWrapper.classList.add("image-control-wrapper--resizing");
    image.style.height = `${height}px`;
    image.style.width = `${width}px`;

    document.addEventListener("pointermove", handlePointerMove);
    document.addEventListener("pointerup", handlePointerUp);
  };

  return (
    <div
      className="absolute inset-0 [&.image-control-wrapper--resizing]:touch-none"
      ref={controlWrapperRef}
    >
      {CORNER_DIRECTIONS.map((direction) => (
        <div
          className={`absolute size-2 rounded-full border border-background/20 bg-foreground shadow-sm ${CORNER_CLASSES[direction]}`}
          key={direction}
          onPointerDown={(event) => handlePointerDown(event, direction)}
        />
      ))}
    </div>
  );
}

const IMAGE_MIME_PREFIX = "image/";

export const isImageFile = (file: File): boolean => {
  return file.type.startsWith(IMAGE_MIME_PREFIX);
};

export const getFirstImageFile = (files: Iterable<File>): File | null => {
  for (const file of files) {
    if (isImageFile(file)) {
      return file;
    }
  }

  return null;
};

export const readFileAsDataUrl = async (file: File): Promise<string> => {
  return await new Promise((resolve, reject) => {
    const reader = new FileReader();

    reader.addEventListener("load", () => {
      if (typeof reader.result === "string") {
        resolve(reader.result);
        return;
      }

      reject(new Error("Image file could not be read as a data URL."));
    });

    reader.addEventListener("error", () => {
      reject(reader.error ?? new Error("Failed to read image file."));
    });

    reader.readAsDataURL(file);
  });
};

